import{_ as o,o as c,c as r,ak as d}from"./chunks/framework.Dru0zOzN.js";const y=JSON.parse('{"title":"项目结构","description":"","frontmatter":{},"headers":[],"relativePath":"Zephyr RTOS/项目结构.md","filePath":"Zephyr RTOS/项目结构.md"}'),l={name:"Zephyr RTOS/项目结构.md"};function a(i,e,p,t,h,s){return c(),r("div",null,[...e[0]||(e[0]=[d('<h1 id="项目结构" tabindex="-1">项目结构 <a class="header-anchor" href="#项目结构" aria-label="Permalink to “项目结构”">​</a></h1><p>zephyr主要有两部分组成： Zephyrproject 目录和 Zephyr SDK 目录。</p><h2 id="zephyrproject-根目录" tabindex="-1">zephyrproject 根目录 <a class="header-anchor" href="#zephyrproject-根目录" aria-label="Permalink to “zephyrproject 根目录”">​</a></h2><p>Zephyrproject 目录是利用 <code>west update</code> 过程中构建的。这是 Zephyr 的工作目录。其包含了：</p><ul><li><code>.west/</code> ：存放了 west 的配置文件，记录当前工作空间引用的仓库信息等。</li><li><code>zephyr/</code> ：是 Zephyr RTOS 的核心仓库。包含了 Zephyr RTOS Core（内核），驱动接口、构建系统等。</li><li><code>modules/</code>：：存放外部的开源组件，包括芯片厂商的 HAL库（比如 hal_stm32）、文件系统（fatfs）等。</li><li><code>bootloader/</code> ：包含了引导加载程序等（mcuboot）。</li><li><code>tools/</code> ：一些辅助脚本和工具。</li></ul><h3 id="zephyr-核心目录" tabindex="-1">zephyr 核心目录 <a class="header-anchor" href="#zephyr-核心目录" aria-label="Permalink to “zephyr 核心目录”">​</a></h3><p>对于其中的 <code>zephyr/</code> 仓库，有一系列需要关注的子目录：</p><ul><li><code>arch/</code> ：包含了架构相关的代码，比如 ARM、x86、RISC-V、Xtensa 等处理器架构的底层实现（比如中断处理、上下文切换等）。</li><li><code>soc/</code>：包含了芯片级相关的适配代码，比如 stm32、nrf52、esp32 等，包含了对于特定芯片的外设描述逻辑，比如时钟、电源管理、引脚复用等。</li><li><code>boards/</code>：包含了部分开发板的定义。对于每一个板子，都包含了 DeviceTree（.dts 文件）用以描述其硬件资源，以及其他配置文件。</li><li><code>drivers/</code>：包含了设备驱动。其按照类别分类（如 <code>gpio/</code>、<code>i2c/</code> 等。其中包含了对于不同芯片厂商的外设驱动，并映射为一套通用的 API。</li><li><code>include/</code> ：公共头文件。包含了一套通用的 API。</li><li><code>kernel/</code>：内核核心。包含了如任务调度、信号量、互斥锁等 RTOS 核心组件。</li><li><code>samples/</code>：示例代码。</li><li><code>subsys/</code>：子系统，包含对于网络协议栈（ip等），文件系统，shell，图形库等。</li><li><code>scripts/</code>： 用于构建调试等的脚本。</li><li><code>dts/</code> ：包含了用于外设硬件描述的模板文件。</li><li><code>lib/</code>：包含了通用的 C 库实现，比如适配版本的 libc 等。</li><li><code>misc/</code>：杂项。</li></ul><h2 id="zephyr-sdk-目录" tabindex="-1">Zephyr SDK 目录 <a class="header-anchor" href="#zephyr-sdk-目录" aria-label="Permalink to “Zephyr SDK 目录”">​</a></h2><p>zephyr sdk 为独立的工具包，通常在 zephyrproject 之外。其提供了交叉编译器和调试工具。</p><p>其内部项目结构包含了独立的各架构工具链，如 <code>arm—zephyr-eabi/</code>，其中包含了<code>gcc</code>，<code>gdb</code> 等编译所用的工具等。</p>',11)])])}const _=o(l,[["render",a]]);export{y as __pageData,_ as default};
